def generate_strobogrammatic(n: int) -> list[str]:
    if n == 0:
        return []

    pairs = [("0", "0"), ("1", "1"), ("6", "9"), ("8", "8"), ("9", "6")]
    mid_digits = ["0", "1", "8"]

    def helper(k):
        if k == 0:
            return [""]
        if k == 1:
            return mid_digits

        prev_results = helper(k - 2)
        current_results = []

        for s in prev_results:
            for left, right in pairs:
                if k == n and left == "0" and n > 1:
                    continue
                current_results.append(left + s + right)
        return current_results

    return helper(n)
